#
# The YAML is the source of authority. Any change to states, events,
# guards, or transitions must originate in the YAML and propagate here.

from dataclasses import dataclass
from typing import Literal, TypedDict, Union

from guards import (
    guard_has_completion_verification_gate,
    guard_superseding_spec_accepted,
)

State = Literal[
    "draft",
    "under_review",
    "accepted",
    "complete",
    "superseded",
    "withdrawn",
    "rejected",
]

Event = Literal[
    "submit_for_review",
    "request_changes",
    "accept",
    "reject",
    "implement_and_verify",
    "supersede",
    "withdraw",
]

GuardName = Literal[
    "has_completion_verification_gate",
    "superseding_spec_accepted",
]


class TransitionContext(TypedDict, total=False):
    has_completion_verification_gate: bool
    superseding_spec_accepted: bool


@dataclass(frozen=True)
class Transition:
    from_state: State
    to_state: State
    event: Event
    guard: GuardName | None = None


TRANSITIONS: tuple[Transition, ...] = (
    Transition("draft",        "under_review", "submit_for_review"),
    Transition("under_review", "draft",        "request_changes"),
    Transition("under_review", "accepted",     "accept"),
    Transition("under_review", "rejected",     "reject"),
    Transition("draft",        "withdrawn",    "withdraw"),
    Transition("accepted",     "complete",     "implement_and_verify", "has_completion_verification_gate"),
    Transition("accepted",     "superseded",   "supersede",            "superseding_spec_accepted"),
    Transition("complete",     "superseded",   "supersede",            "superseding_spec_accepted"),
)

TERMINAL_STATES: tuple[State, ...] = (
    "complete",
    "superseded",
    "withdrawn",
    "rejected",
)

# States that are terminal but admit a documented exception
# (re_entry_allowed: true in the YAML). Only "complete" qualifies.
RE_ENTRY_ALLOWED_STATES: tuple[State, ...] = ("complete",)


@dataclass(frozen=True)
class Allowed:
    next_state: State
    kind: Literal["allowed"] = "allowed"


@dataclass(frozen=True)
class Refused:
    reason: Literal["no_matching_transition", "guard_false"]
    kind: Literal["refused"] = "refused"


TransitionResult = Union[Allowed, Refused]


def evaluate_guard(name: GuardName, context: TransitionContext) -> bool:
    match name:
        case "has_completion_verification_gate":
            return guard_has_completion_verification_gate(context)
        case "superseding_spec_accepted":
            return guard_superseding_spec_accepted(context)


def apply_transition(
    current: State,
    event: Event,
    context: TransitionContext | None = None,
) -> TransitionResult:
    ctx: TransitionContext = context or {}

    candidates = [t for t in TRANSITIONS if t.from_state == current and t.event == event]

    if not candidates:
        return Refused(reason="no_matching_transition")

    for t in candidates:
        if t.guard is None:
            return Allowed(next_state=t.to_state)
        if evaluate_guard(t.guard, ctx):
            return Allowed(next_state=t.to_state)

    return Refused(reason="guard_false")
